// Procesar webhook de Telegram
const inputData = $input.first().json;
// El webhook puede enviar datos en body o directamente
const update = inputData.body || inputData;
const message = update.message;

if (!message || !message.text) {
  return [];
}

const chatId = message.chat.id;
const messageText = message.text.trim();
const userId = message.from.id;
const userName = message.from.first_name || message.from.username || 'Usuario';

// Variables para la respuesta
let response = '';
let processInvoice = false;
let userData = {};

// Procesar comandos
if (messageText.toLowerCase() === '/start' || messageText.toLowerCase() === 'hola') {
  response = `👋 ¡Hola ${userName}! Soy tu asistente para generar facturas AFIP.\n\n` +
           "📋 Para crear una factura, envía los datos en este formato (separados por líneas):\n\n" +
           "1️⃣ Nombre del cliente\n" +
           "2️⃣ DNI/CUIT\n" +
           "3️⃣ Dirección completa\n" +
           "4️⃣ País\n" +
           "5️⃣ Descripción del servicio\n" +
           "6️⃣ Monto en USD\n" +
           "7️⃣ Cantidad\n" +
           "8️⃣ Método de pago\n\n" +
           "📝 *Ejemplo:*\n" +
           "Juan Pérez\n" +
           "12345678901\n" +
           "Av. Corrientes 1234, CABA\n" +
           "Argentina\n" +
           "Servicios de consultoría\n" +
           "1500\n" +
           "1\n" +
           "transferencia";

} else if (messageText.toLowerCase() === '/cancel') {
  response = "❌ Proceso cancelado. Escribe /start para comenzar nuevamente.";

} else if (messageText.toLowerCase() === '/help') {
  response = "🆘 *Ayuda - Bot de Facturas AFIP*\n\n" +
           "*Comandos disponibles:*\n" +
           "/start - Iniciar proceso\n" +
           "/help - Mostrar ayuda\n" +
           "/cancel - Cancelar\n\n" +
           "*Para generar una factura:*\n" +
           "Envía los datos en 8 líneas separadas como se muestra en /start";

} else {
  // Procesar datos de factura
  const lines = messageText.split('\n').map(line => line.trim()).filter(line => line.length > 0);

  if (lines.length >= 8) {
    const [clientName, clientDni, clientAddress, clientCountry, description, amount, quantity, paymentMethod] = lines;

    // Validaciones
    const amountNum = parseFloat(amount);
    const quantityNum = parseInt(quantity);

    if (isNaN(amountNum) || amountNum <= 0) {
      response = "❌ *Error en el monto*\n\nEl monto debe ser un número válido mayor a 0.\n\nEjemplo: 1500";
    } else if (isNaN(quantityNum) || quantityNum <= 0) {
      response = "❌ *Error en la cantidad*\n\nLa cantidad debe ser un número entero mayor a 0.\n\nEjemplo: 1";
    } else {
      // Generar fechas automáticamente
      const today = new Date();
      const invoiceDate = today.toISOString().slice(0, 10).replace(/-/g, '');
      const paymentDate = new Date(today.getTime() + (30 * 24 * 60 * 60 * 1000)).toISOString().slice(0, 10).replace(/-/g, '');

      userData = {
        client_name: clientName,
        client_dni: clientDni,
        client_address: clientAddress,
        client_country: clientCountry,
        client_country_code: clientCountry.toLowerCase() === 'argentina' ? 200 : 212,
        client_cuit_country: clientDni,
        invoice_description: description,
        invoice_amount: amountNum,
        invoice_quantity: quantityNum,
        invoice_date: invoiceDate,
        payment_method: paymentMethod,
        payment_date: paymentDate,
        chat_id: chatId
      };

      response = "📋 *Datos recibidos correctamente* ✅\n\n" +
               "*Resumen de la factura:*\n" +
               `👤 Cliente: ${userData.client_name}\n` +
               `🆔 DNI/CUIT: ${userData.client_dni}\n` +
               `📍 Dirección: ${userData.client_address}\n` +
               `🌍 País: ${userData.client_country}\n` +
               `📝 Descripción: ${userData.invoice_description}\n` +
               `💰 Monto: $${userData.invoice_amount} USD\n` +
               `📦 Cantidad: ${userData.invoice_quantity}\n` +
               `💳 Pago: ${userData.payment_method}\n\n` +
               "⏳ *Procesando factura en AFIP...*";

      processInvoice = true;
    }
  } else {
    response = "❌ *Datos incompletos*\n\n" +
             `Recibí ${lines.length} línea(s), pero necesito exactamente 8 líneas.\n\n` +
             "Por favor, envía todos los datos juntos separados por líneas. Usa /start para ver el formato.";
  }
}

return [{
  userPhone: chatId,
  response: response,
  processInvoice: processInvoice,
  invoiceData: processInvoice ? userData : null,
  userName: userName
}];

// Obtener datos del formulario
const formData = $input.first().json;

// Valores por defecto
const defaults = {
  client_name: "Ontop Holdings Inc",
  client_dni: "301247689",
  client_address: "251 little driver, wilmington, new castle country, delaware, 19808",
  client_country: "ESTADOS UNIDOS",
  client_country_code: 212,
  client_cuit_country: "55000002126",
  invoice_description: "Honorarios Profesionales correspondiente al mes de febrero del año 2025",
  invoice_amount: 1400,
  invoice_quantity: 1,
  invoice_date: "20250720",
  payment_method: "transferencia",
  payment_date: "20250730"
};

// Mapear datos del formulario o usar valores por defecto si están vacíos
const invoiceData = {
  client_name: formData.client_name || defaults.client_name,
  client_dni: formData.client_dni || defaults.client_dni,
  client_address: formData.client_address || defaults.client_address,
  client_country: formData.client_country || defaults.client_country,
  client_country_code: formData.client_country_code || defaults.client_country_code,
  client_cuit_country: formData.client_cuit_country || defaults.client_cuit_country,
  invoice_description: formData.invoice_description || defaults.invoice_description,
  invoice_amount: formData.invoice_amount || defaults.invoice_amount,
  invoice_quantity: formData.invoice_quantity || defaults.invoice_quantity,
  invoice_date: formData.invoice_date || defaults.invoice_date,
  payment_method: formData.payment_method || defaults.payment_method,
  payment_date: formData.payment_date || defaults.payment_date,
  chat_id: formData.chat_id
};

return [invoiceData];

// Datos para el QR (Respetar si es string o numero)
const r = $input.first().json.FEXAuthorizeResult.FEXResultAuth;
const triggerData = $('Set Invoice Data').item.json;
const QRCodeData = {
    'ver': 1,
    'fecha': r.Fch_cbte,
    'cuit': Number(r.Cuit),
    'ptoVta': Number(r.Punto_vta),
    'tipoCmp': Number(r.Cbte_tipo),
    'nroCmp': Number(r.Cbte_nro),
    'importe': Number(triggerData.invoice_amount),
    'moneda': "DOL",
    'ctz': 2,
    'tipoDocRec': 99,
    'nroDocRec': Number(triggerData.client_dni),
    'tipoCodAut': 'E',
    'codAut': Number(r.Cae)
};
const QRCodeText = 'https://www.afip.gob.ar/fe/qr/?p=' + Buffer.from(JSON.stringify(QRCodeData)).toString('base64');
return [{ 
  qr_code_text: QRCodeText,
  voucher_result: r,
  chat_id: triggerData.chat_id,
  invoice_data: triggerData
}];

